INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic) VALUES
('22b0cf5e-6bad-5fb3-a740-f3d25ba4e371', '8b3242aa-721e-485b-a282-9f1917c6f65d', 'He has ___ unique way of solving math problems.', '他有一種獨特的方法來解決數學問題。', 'a', 'some', 'any', 'each', 'a 為不定冠詞，用於單數可數名詞前，表示「一種」。', 'a 代表 one (一個)。'),
('82115e03-ae4d-57c2-9d82-97a8d3f420f5', '24837458-0d4f-4a59-9dc7-ae944f0f278c', 'The main difficulty in learning a new language ___ mastering its grammar.', '學習一門新語言的主要困難在於掌握其語法。', 'is', 'has', 'does', 'says', 'be 動詞的第三人稱單數現在式', 'is 代表「是」或「在」，用於描述主詞的狀態或身分。'),
('d6a30862-b197-5b9a-83ec-36c616b005f1', '8fecc1f7-8571-4e65-874e-7bec724d9609', '___ sun rises in the east every morning.', '太陽每天早晨從東方升起。', 'The', 'A', 'Some', 'Any', '定冠詞 (Definite Article)', '獨一無二的事物用 the'),
('753527cb-9dc9-52d4-b92b-1ca5c504fcdd', '1d86e27e-0866-4c5e-8277-4bc91cc8ab5e', 'I didn''t realize the problem was ___ serious.', '我沒意識到問題有那麼嚴重。', 'that', 'very', 'so', 'too', '副詞 (adv.)，用於否定句中，表示「那麼」或「那樣地」。', 'That (那麼) → 表示程度的強調。');
